import{u as s,o as l,c as r,x as i}from"./NH8k3hJr.js";const n=s("/docs/sms/s1.png"),g=s("/docs/sms/s2.png"),c=s("/docs/sms/s3.png"),S=s("/docs/sms/s4.png"),m=s("/docs/sms/s5.png"),p=s("/docs/sms/s6.png"),e={class:"markdown-body"},u={__name:"SMS: Подключение",setup(h,{expose:t}){return t({frontmatter:{}}),(_,o)=>(l(),r("div",e,[...o[0]||(o[0]=[i('<h1>Инструкция по подключению SMS</h1><hr><h2>Шаг 1. Добавить аккаунт SMS</h2><ol><li>Зайдите в раздел <strong>Настройки → Интеграции → SMS</strong>.</li><li>Нажмите <strong>«Добавить аккаунт»</strong>.</li><li>Выберите вид аккаунта — <strong>SMS</strong>.</li><li>Примите условия работы канала SMS и нажмите <strong>«Сохранить»</strong>.</li></ol><p><img src="'+n+'" alt="Описание картинки"></p><hr><h2>Шаг 2. Включить аккаунт</h2><ol><li>В списке аккаунтов найдите созданный <strong>SMS</strong>.</li><li>Нажмите <strong>«Включить»</strong>. <img src="'+g+'" alt="Описание картинки"></li></ol><hr><h2>Шаг 3. Установить приложение на телефон</h2><ol><li>Система предложит установить приложение из <strong>RuStore</strong>.</li><li>Скачайте и установите приложение.</li><li>Вернитесь в личный кабинет и нажмите <strong>«Я уже скачал»</strong>.</li></ol><h2><img src="'+c+'" alt="Описание картинки"></h2><h2>Шаг 4. Авторизоваться в приложении</h2><ol><li>Запустите приложение на телефоне.</li><li>Выдайте все необходимые разрешения (доступ к SMS, контактам, работе в фоне).</li><li>Нажмите <strong>«Отсканировать QR-код»</strong>.</li><li>Наведите камеру на QR-код, который отобразится в личном кабинете. <img src="'+S+'" alt="Описание картинки"></li></ol><hr><h2>Шаг 5. Запустить рассылку</h2><ol><li>После успешной авторизации в приложении нажмите <strong>«Начать рассылку»</strong>.</li><li><strong>Важно:</strong> если не нажать <strong>«Начать рассылку»</strong>, сообщения будут накапливаться в очереди и отправятся только после запуска. <img src="'+m+'" alt="Описание картинки"></li></ol><hr><h2>Шаг 6. Настроить каскад (группу отправки)</h2><ol><li>Перейдите в раздел <strong>Аккаунты → Группы</strong>.</li><li>Откройте группу <strong>Default cascade group</strong> (или создайте новую).</li><li>Добавьте аккаунт <strong>SMS</strong> в группу.</li><li>Обязательно поставьте <strong>SMS</strong> на последнее место в порядке отправки.</li></ol><blockquote><p><strong>Внимание:</strong> если SMS стоит выше Telegram или WhatsApp — все сообщения будут уходить через SMS, и затраты на рассылку возрастут. До остальных каналов очередь просто не дойдёт.</p></blockquote><h2><img src="'+p+'" alt="Описание картинки"></h2><h2>Рекомендации для стабильной работы</h2><ul><li>Держите телефон на зарядке.</li><li>Не выключайте экран во время активной рассылки.</li><li>Не закрывайте приложение <strong>SMS API</strong>.</li></ul>',24)])]))}};export{u as default};
